package dev.harrison.rendacomcarro.attachment.web;import dev.harrison.rendacomcarro.attachment.application.AttachmentService;import java.util.UUID;import org.springframework.http.*;import org.springframework.stereotype.Controller;import org.springframework.web.bind.annotation.*;import org.springframework.core.io.Resource;
@Controller@RequestMapping("/attachments")public class AttachmentController {private final AttachmentService service;public AttachmentController(AttachmentService s){service=s;}@GetMapping("/{id}")public ResponseEntity<Resource> download(@PathVariable UUID id){var a=service.get(id);return ResponseEntity.ok().contentType(MediaType.parseMediaType(a.getContentType())).header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=\""+a.getOriginalFilename().replace("\"","")+"\"").contentLength(a.getSizeBytes()).body(service.content(id));}}
